draw((-2,0)--(5,0));
draw((0,-1)--(0,4));
draw(O--A,Arrow(6));
draw(O--B,Arrow(6));
draw(O--P,Arrow(6));
draw(interp(A,B,-0.1)--interp(A,B,1.1),dashed);

label("$\begin{pmatrix} 4 \\ 1 \end{pmatrix}$", A, N);
label("$\begin{pmatrix} -1 \\ 3 \end{pmatrix}$", B, N);
label("$\mathbf{p}$", P, N);
[/asy]

